/* ============================================================
   AUTO UNIVERSE — VENDOR / FONT
   DejaVu Sans (subset: latinica + š/ć/č/ž/đ) za jsPDF.
   Rešava kvačice u PDF-u (Sesija 5). Bundlovano lokalno.
   Registruje "DejaVu" font sa normal+bold varijantama.
   ============================================================ */
(function (global) {
  "use strict";
  var REG = "";
  var BOLD = "";

  function register(doc) {
    try {
      doc.addFileToVFS("DejaVu-Regular.ttf", REG);
      doc.addFont("DejaVu-Regular.ttf", "DejaVu", "normal");
      doc.addFileToVFS("DejaVu-Bold.ttf", BOLD);
      doc.addFont("DejaVu-Bold.ttf", "DejaVu", "bold");
      return true;
    } catch (e) {
      return false; // fallback na helvetica ako nešto pukne
    }
  }

  global.AUFont = { register: register, name: "DejaVu" };
  if (typeof module !== "undefined" && module.exports) module.exports = global.AUFont;
})(typeof window !== "undefined" ? window : globalThis);
